import { describe, expect, test } from 'vitest';
import {
  parsePrUrl,
  applyPrUrlTemplate,
  type PrHostInfo,
} from '../../lib/pr-host-parser.js';

describe('parsePrUrl', () => {
  describe('github.com', () => {
    test('parses public github.com PR URL', () => {
      const r = parsePrUrl('https://github.com/yonatangross/orchestkit/pull/1496');
      expect(r).toMatchObject({
        host: 'github.com',
        family: 'github',
        owner: 'yonatangross',
        repo: 'orchestkit',
        pr_id: 1496,
      });
    });

    test('strips query string and fragment', () => {
      const r = parsePrUrl('https://github.com/owner/repo/pull/42?diff=split#review');
      expect(r?.pr_id).toBe(42);
    });

    test('http (not https) is accepted', () => {
      const r = parsePrUrl('http://github.com/owner/repo/pull/1');
      expect(r?.family).toBe('github');
    });
  });

  describe('GitHub Enterprise', () => {
    test('parses *.github.<tld> URL as github-enterprise', () => {
      const r = parsePrUrl('https://acme.github.io/team/svc/pull/77');
      expect(r).toMatchObject({
        family: 'github-enterprise',
        host: 'acme.github.io',
        owner: 'team',
        repo: 'svc',
        pr_id: 77,
      });
    });
  });

  describe('GitLab.com', () => {
    test('parses gitlab.com MR URL', () => {
      const r = parsePrUrl('https://gitlab.com/group/project/-/merge_requests/12');
      expect(r).toMatchObject({
        family: 'gitlab',
        host: 'gitlab.com',
        owner: 'group',
        repo: 'project',
        pr_id: 12,
      });
    });

    test('parses nested group MR URL', () => {
      const r = parsePrUrl('https://gitlab.com/group/subgroup/project/-/merge_requests/9');
      expect(r).toMatchObject({
        family: 'gitlab',
        owner: 'group/subgroup',
        repo: 'project',
        pr_id: 9,
      });
    });
  });

  describe('Self-hosted GitLab', () => {
    test('parses gitlab.<corp> MR URL', () => {
      const r = parsePrUrl('https://gitlab.acme.io/team/repo/-/merge_requests/3');
      expect(r).toMatchObject({
        family: 'gitlab-self',
        host: 'gitlab.acme.io',
      });
    });
  });

  describe('Bitbucket Cloud', () => {
    test('parses bitbucket.org PR URL', () => {
      const r = parsePrUrl('https://bitbucket.org/workspace/repo/pull-requests/5');
      expect(r).toMatchObject({
        family: 'bitbucket',
        host: 'bitbucket.org',
        owner: 'workspace',
        repo: 'repo',
        pr_id: 5,
      });
    });
  });

  describe('rejection cases', () => {
    test('returns null for non-PR github URL', () => {
      expect(parsePrUrl('https://github.com/owner/repo/issues/1')).toBeNull();
    });

    test('returns null for empty string', () => {
      expect(parsePrUrl('')).toBeNull();
    });

    test('returns null for non-string input', () => {
      // @ts-expect-error testing runtime safety
      expect(parsePrUrl(null)).toBeNull();
      // @ts-expect-error testing runtime safety
      expect(parsePrUrl(123)).toBeNull();
    });

    test('returns null for malformed URL', () => {
      expect(parsePrUrl('not a url')).toBeNull();
    });

    test('returns null when pr_id is not numeric', () => {
      expect(parsePrUrl('https://github.com/o/r/pull/abc')).toBeNull();
    });

    test('returns null for unknown host (no fallback in parser)', () => {
      expect(parsePrUrl('https://random.example.com/o/r/pull/1')).toBeNull();
    });
  });
});

describe('applyPrUrlTemplate', () => {
  const sample: PrHostInfo = {
    host: 'gitlab.acme.io',
    family: 'gitlab-self',
    owner: 'team',
    repo: 'svc',
    pr_id: 42,
  };

  test('substitutes all four tokens', () => {
    const out = applyPrUrlTemplate(
      'https://{host}/{owner}/{repo}/-/merge_requests/{n}',
      sample,
    );
    expect(out).toBe('https://gitlab.acme.io/team/svc/-/merge_requests/42');
  });

  test('leaves unknown tokens unchanged', () => {
    const out = applyPrUrlTemplate('{host}/{branch}/{n}', sample);
    expect(out).toBe('gitlab.acme.io/{branch}/42');
  });

  test('handles repeated tokens', () => {
    const out = applyPrUrlTemplate('{host}+{host}', sample);
    expect(out).toBe('gitlab.acme.io+gitlab.acme.io');
  });
});
